import{_ as t,c as s,o as r,ae as i}from"./chunks/framework.Cd-3tpCq.js";const h=JSON.parse('{"title":"🎬 Le projet : CinéCritique","description":"","frontmatter":{},"headers":[],"relativePath":"drupal-project/create-project.md","filePath":"drupal-project/create-project.md"}'),a={name:"drupal-project/create-project.md"};function n(o,e,l,p,d,c){return r(),s("div",null,e[0]||(e[0]=[i(`<h1 id="🎬-le-projet-cinecritique" tabindex="-1">🎬 Le projet : CinéCritique <a class="header-anchor" href="#🎬-le-projet-cinecritique" aria-label="Permalink to &quot;🎬 Le projet : CinéCritique&quot;">​</a></h1><p>Pour rendre cette formation concrète, nous allons construire ensemble un <strong>site de notation et d&#39;avis de films</strong>, inspiré de plateformes comme <a href="https://letterboxd.com/" target="_blank" rel="noreferrer">Letterboxd</a>.</p><h2 id="fonctionnalites-prevues" tabindex="-1">Fonctionnalités prévues <a class="header-anchor" href="#fonctionnalites-prevues" aria-label="Permalink to &quot;Fonctionnalités prévues&quot;">​</a></h2><p>Notre site <strong>CinéCritique</strong> proposera :</p><table tabindex="0"><thead><tr><th>Fonctionnalité</th><th>Description</th></tr></thead><tbody><tr><td>🎥 <strong>Fiches films</strong></td><td>Chaque film aura sa fiche : titre, synopsis, affiche, date de sortie, genre, durée…</td></tr><tr><td>⭐ <strong>Notation</strong></td><td>Les utilisateurs pourront attribuer une note sur 5 à chaque film</td></tr><tr><td>💬 <strong>Avis / Critiques</strong></td><td>Les utilisateurs pourront rédiger un avis détaillé sur un film</td></tr><tr><td>👤 <strong>Comptes utilisateurs</strong></td><td>Inscription, connexion et profil utilisateur</td></tr><tr><td>🔍 <strong>Recherche et filtres</strong></td><td>Rechercher un film par titre, genre ou année</td></tr></tbody></table><h2 id="preparer-l-espace-de-travail" tabindex="-1">Préparer l&#39;espace de travail <a class="header-anchor" href="#preparer-l-espace-de-travail" aria-label="Permalink to &quot;Préparer l&#39;espace de travail&quot;">​</a></h2><p>Avant de lancer la moindre installation, nous allons préparer la structure de notre projet.</p><h3 id="creer-le-dossier-du-projet" tabindex="-1">Créer le dossier du projet <a class="header-anchor" href="#creer-le-dossier-du-projet" aria-label="Permalink to &quot;Créer le dossier du projet&quot;">​</a></h3><p>Ouvrez un terminal <strong>WSL</strong> (Ubuntu) et créez un dossier dédié à vos projets, puis le dossier du projet :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Créer un dossier pour regrouper tous vos projets (si ce n&#39;est pas déjà fait)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/projets</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Créer le dossier du projet CinéCritique</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/projets/cinecritique</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Se placer dans le dossier</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/projets/cinecritique</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">❓ Où se trouve ce dossier ?</p><p>Sous Windows, le dossier est accessible depuis l&#39;explorateur de fichiers à l&#39;adresse : <code>\\\\wsl.localhost\\Ubuntu\\home\\UTILISATEUR\\projets\\cinecritique</code></p><p>Remplacez <em>UTILISATEUR</em> par votre nom d&#39;utilisateur Linux (WSL).</p></div><div class="danger custom-block"><p class="custom-block-title">🚨 Important</p><p>Travaillez toujours depuis le système de fichiers Linux (dans WSL) et non depuis un dossier Windows classique (C:\\Users...). Les performances de Docker et DDEV sont nettement meilleures sur le système de fichiers Linux.</p></div><h2 id="versionnage-avec-git-recommande" tabindex="-1">Versionnage avec Git (recommandé) <a class="header-anchor" href="#versionnage-avec-git-recommande" aria-label="Permalink to &quot;Versionnage avec Git (recommandé)&quot;">​</a></h2><p>Il est fortement recommandé d&#39;utiliser Git pour versionner votre projet dès le départ. Cela vous permettra de :</p><ul><li>💾 Sauvegarder chaque étape de votre progression</li><li>↩️ Revenir en arrière en cas d&#39;erreur</li><li>👥 Collaborer avec d&#39;autres développeurs</li><li>☁️ Héberger votre code sur une plateforme comme GitHub ou GitLab</li></ul><p>Pour initialiser un dépôt Git dans votre projet :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/projets/cinecritique</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Drupal va devoir attendre encore un peu !</p><p>Car nous allons d&#39;abord nous intéresser à un outil qui va nous permettre de mettre en place rapidement un environnement de développement local : <a href="/drupal-project/installation/ddev.html">DDEV</a>.</p></div>`,18)]))}const m=t(a,[["render",n]]);export{h as __pageData,m as default};
